73	int greedy_best_dest(const State& S, int target) {
74	    int src = S.box_stack[target];
75	    int h = S.box_height[target];
76	    int num_on_top = S.stack_size[src] - 1 - h;
77	    int M = S.M;
78	
79	    if (num_on_top == 0) return src;
80	
81	    double best_score = 1e18;
82	    int best_dest = (src + 1) % M;
83	
84	    for (int d = 0; d < M; d++) {
85	        if (d == src) continue;
86	        double score = 0.0;
87	
88	        for (int j = 0; j < S.stack_size[d]; j++) {
89	            int box_in_dest = S.stacks[d][j];
90	            if (box_in_dest > target && box_in_dest < target + 25) {
91	                int boxes_above_after = (S.stack_size[d] - 1 - j) + num_on_top;
92	                double urgency = 25.0 / (box_in_dest - target);
93	                score += urgency * boxes_above_after * 0.8;
94	            }
95	        }
96	
97	        for (int i = 0; i < num_on_top; i++) {
98	            int box_in_block = S.stacks[src][h + 1 + i];
99	            if (box_in_block > target && box_in_block < target + 25) {
100	                int final_boxes_above = num_on_top - 1 - i;
101	                double urgency = 25.0 / (box_in_block - target);
102	                score += urgency * final_boxes_above * 0.5;
103	            }
104	        }
105	
106	        if (S.stack_size[d] == 0) score += 80.0;
107	        score += S.stack_size[d] * 0.5;
108	
109	        int top_of_block = S.stacks[src][h + num_on_top];
110	        if (top_of_block > target && top_of_block < target + 5) {
111	            score -= 15.0;
112	        }
113	
114	        if (score < best_score) { best_score = score; best_dest = d; }
115	    }
