// Phase 2: SA with checkpointed partial simulation
int current_plan[MAX_N];
memcpy(current_plan, best_plan, sizeof(int) * N);
long long current_energy = best_energy;

// Build checkpoints: save state at intervals so we can resume from mutation point
const int CP_INTERVAL = 10;
const int NUM_CP = (N + CP_INTERVAL - 1) / CP_INTERVAL;
std::vector<State> checkpoints(NUM_CP + 1);

auto rebuild_checkpoints = [&]() {
    checkpoints[0].init(N, M, initial_stacks);
    for (int k = 0; k < N; k++) {
        if (k % CP_INTERVAL == 0 && k > 0) {
            checkpoints[k / CP_INTERVAL] = checkpoints[k / CP_INTERVAL - 1];
            State& cp = checkpoints[k / CP_INTERVAL];
            for (int kk = (k / CP_INTERVAL - 1) * CP_INTERVAL; kk < k; kk++) {
                int src = cp.box_stack[kk];
                int h = cp.box_height[kk];
                int num_on_top = cp.stack_size[src] - 1 - h;
                if (num_on_top > 0) {
                    int dest = current_plan[kk];
                    if (dest == src) dest = (src + 1) % M;
                    cp.move_block(cp.stacks[src][h + 1], num_on_top, dest);
                }
                cp.carry_out(kk);
            }
        }
    }
    // Build last checkpoint
    int last_cp = (N - 1) / CP_INTERVAL;
    if (last_cp > 0) {
        checkpoints[last_cp] = checkpoints[last_cp - 1];
        State& cp = checkpoints[last_cp];
        for (int kk = (last_cp - 1) * CP_INTERVAL; kk < last_cp * CP_INTERVAL && kk < N; kk++) {
            int src = cp.box_stack[kk];
            int h = cp.box_height[kk];
            int num_on_top = cp.stack_size[src] - 1 - h;
            if (num_on_top > 0) {
                int dest = current_plan[kk];
                if (dest == src) dest = (src + 1) % M;
                cp.move_block(cp.stacks[src][h + 1], num_on_top, dest);
            }
            cp.carry_out(kk);
        }
    }
};

// Simulate from a given index using checkpoints
auto simulate_from = [&](int from_idx) -> long long {
    int cp_idx = from_idx / CP_INTERVAL;
    State S = checkpoints[cp_idx];
    int start_k = cp_idx * CP_INTERVAL;
    for (int k = start_k; k < N; k++) {
        int src = S.box_stack[k];
        int h = S.box_height[k];
        int num_on_top = S.stack_size[src] - 1 - h;
        if (num_on_top > 0) {
            int dest = current_plan[k];
            if (dest == src) dest = (src + 1) % M;
            S.move_block(S.stacks[src][h + 1], num_on_top, dest);
        }
        S.carry_out(k);
    }
    return S.energy;
};

rebuild_checkpoints();

const double SA_END_TIME = 1.75;
double sa_start = elapsed_seconds();
double sa_budget = SA_END_TIME - sa_start;
double T_init = 8.0;
double T_final = 0.5;
double current_T = T_init;
int rebuild_counter = 0;

while (true) {
    double now = elapsed_seconds();
    if (now >= SA_END_TIME) break;
    double progress = (now - sa_start) / sa_budget;
    current_T = T_init * std::pow(T_final / T_init, std::min(1.0, progress));

    for (int batch = 0; batch < 128; batch++) {
        int idx1 = RGen.an_int(0, N - 1);
        int old_val1 = current_plan[idx1];
        current_plan[idx1] = RGen.an_int(0, M - 1);

        int idx2 = -1, old_val2 = 0;
        if (RGen.an_int(0, 9) < 3 && idx1 + 1 < N) {
            idx2 = idx1 + 1;
            old_val2 = current_plan[idx2];
            current_plan[idx2] = RGen.an_int(0, M - 1);
        }

        long long new_energy = simulate_from(idx1);

        long long delta = new_energy - current_energy;
        if (delta <= 0 || RGen.a_double(0, 1) < std::exp(-(double)delta / current_T)) {
            current_energy = new_energy;
            if (new_energy < best_energy) {
                best_energy = new_energy;
                memcpy(best_plan, current_plan, sizeof(int) * N);
            }
            rebuild_counter++;
            if (rebuild_counter >= 50) {
                rebuild_checkpoints();
                rebuild_counter = 0;
            }
        } else {
            current_plan[idx1] = old_val1;
            if (idx2 >= 0) current_plan[idx2] = old_val2;
        }
    }
}

