137	// Lookahead evaluation: simulate forward W steps greedily from a state,
138	// return total energy for those steps
139	long long lookahead_energy(State S, int start_k, int W) {
140	    long long e0 = S.energy;
141	    int end_k = std::min(start_k + W, S.N);
142	    for (int k = start_k; k < end_k; k++) {
143	        int src = S.box_stack[k];
144	        int h = S.box_height[k];
145	        int num_on_top = S.stack_size[src] - 1 - h;
146	        if (num_on_top > 0) {
147	            int dest = greedy_best_dest(S, k);
148	            if (dest == src) dest = (src + 1) % S.M;
149	            S.move_block(S.stacks[src][h + 1], num_on_top, dest);
150	        }
151	        S.carry_out(k);
152	    }
153	    return S.energy - e0;
154	}
